import{_ as a,p as i,q as e,a1 as l}from"./framework-e0dd9823.js";const o={},t=l('<h1 id="冠词" tabindex="-1"><a class="header-anchor" href="#冠词" aria-hidden="true">#</a> 冠词</h1><p>冠词是一种虚词，没有完整的词义，不能单独使用。冠词非常重要，英语很多词语都需要冠词。</p><p>冠词分为：定冠词和不定冠词</p><h2 id="定冠词-a-an" tabindex="-1"><a class="header-anchor" href="#定冠词-a-an" aria-hidden="true">#</a> 定冠词 a/an</h2><p>用法，a 放在辅音开头的单词前面，例如 a book，a pen。an 放在元音开头的单词前面，例如 an egg，an apple。注意，这个的辅音和元音是指单词的发音（音标符号），而不是指辅音元音字母。例如 a university ,university 是元音开头但是音标是辅音开头的。</p><p>另外，不定冠词也会随着名词直接的定语发生变化，例如：a man, 如果 man 加上了修饰词 old man，这个时候就要用 an old man。</p><p>当表示一个人或一个事物的时候，就在可数名词单数前面加上 a/an 即可。注意，a/an 不能修饰不可数名词和可数名词复数。</p><ul><li>He is a doctor.</li><li>A dog is a cute animal.</li><li>He earns two thoudsad yuan a month.</li></ul><h2 id="定冠词-the" tabindex="-1"><a class="header-anchor" href="#定冠词-the" aria-hidden="true">#</a> 定冠词 the</h2><p>定冠词用法很多，主要用法：</p><ol><li>在普通名词前指一类人或者事物，一般不用翻译出来。</li><li>在重新提及到的人或物，含有“这，这些”的意思，可以修饰可数名词单数、复数和不可数名词。</li><li>在谈话双方都知道的人或物前面，可以修饰可数名词单数、复数和不可数名词。</li><li>在有限定性后置定语修饰的名词前。</li><li>在序数词前面。</li></ol><p>其中 2、3、4 是最常用的，他们都是特指。</p><ul><li>I bought a book yesterday. the book is interesting.</li></ul><h2 id="不用冠词的情况" tabindex="-1"><a class="header-anchor" href="#不用冠词的情况" aria-hidden="true">#</a> 不用冠词的情况</h2><p>英语该用冠词的地方一定要用，不该用冠词的地方一定不能用。用了也能会造成误解。一下列举了不能用冠词的情况：</p><ol><li>专有名词（人名、地名、国名、节日、月份、星期、季节）。</li><li>表示泛指的时候。</li><li>称呼语。</li><li>表示身份、职位、头衔的名词。</li><li>如果一个名词前面已经有形容词性物主代词、名词所有格、指示代词、疑问词以及不定代词做定语的时候。例如：</li></ol><ul><li>Nick&#39;s book 不能说是 Nick&#39;s a book 或 Nick&#39;s the book</li><li>My book 不能说是 My a book 或 My the book</li><li>That book 不能说是 That a book / That the book</li><li>Whose book is this? 不能说是 whose a book / whose the book</li><li>Some place 不能说是 some a place / some the place</li></ul>',17),h=[t];function n(s,r){return i(),e("div",null,h)}const d=a(o,[["render",n],["__file","article.html.vue"]]);export{d as default};
